/**
 * @file test_input_modes.cpp
 * @brief End-to-end tests for all three input modes (VCF-only, VCF+PLINK, PLINK-only)
 *
 * Requires test data generated by generate_test_data (tests/data/test.*)
 */

#include "test_harness.h"
#include "kinship_estimator.h"
#include <cmath>
#include <vector>
#include <fstream>
#include <sys/stat.h>

using namespace fastlckin;

// Check that test data exists
static bool test_data_exists() {
    struct stat st;
    return (stat("tests/data/test.vcf", &st) == 0 &&
            stat("tests/data/test.bed", &st) == 0 &&
            stat("tests/data/test.bim", &st) == 0 &&
            stat("tests/data/test.fam", &st) == 0);
}

TEST_CASE(mode2_vcf_plink_runs) {
    // Mode 2 (VCF+PLINK) should produce valid results
    if (!test_data_exists()) {
        std::cerr << "  SKIP: test data not found (run generate_test_data first)\n";
        return;
    }

    KinshipConfig config;
    config.vcf_path = "tests/data/test.vcf";
    config.plink_prefix = "tests/data/test";
    config.input_mode = InputMode::VCF_PLINK;
    config.output_path = "/tmp/test_mode2_output.tsv";
    config.classify = true;

    KinshipEstimator estimator(config);
    auto results = estimator.run();

    // 20 samples → C(20,2) = 190 pairs
    CHECK(results.size() == 190);

    // All results should have valid IBD coefficients
    for (const auto& r : results) {
        CHECK(!r.failed);
        CHECK(r.k0 >= 0.0 && r.k0 <= 1.0);
        CHECK(r.k1 >= 0.0 && r.k1 <= 1.0);
        CHECK(r.k2 >= 0.0 && r.k2 <= 1.0);
        CHECK_NEAR(r.k0 + r.k1 + r.k2, 1.0, 0.01);
        CHECK(r.pi_hat >= 0.0 && r.pi_hat <= 1.0);
        CHECK(r.n_snps > 0);
    }
}

